import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.DpI_zlPE.js";var i=JSON.parse(`{"title":"人体工程学·桌椅","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/生活/人体工程学.md","filePath":"ccc/生活/人体工程学.md"}`),a={name:`ccc/生活/人体工程学.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="人体工程学·桌椅" tabindex="-1">人体工程学·桌椅 <a class="header-anchor" href="#人体工程学·桌椅" aria-label="Permalink to “人体工程学·桌椅”">​</a></h1><ul><li><p><a href="https://www.ergotron.com/zh-cn/%E5%B7%A5%E5%85%B7/%E5%B7%A5%E4%BD%9C%E7%A9%BA%E9%97%B4%E8%A7%84%E5%88%92%E5%99%A8" target="_blank" rel="noreferrer">ergotron推荐舒适工作区范围</a></p></li><li><p><a href="https://www.bauhutte.jp/bauhutte-life/tip2/" target="_blank" rel="noreferrer">日本网站推荐工作区范围</a>，公式：</p></li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>单位：厘米</span></span>
<span class="line"><span>椅面高度 =（0.25x身高-1 ）四舍五入</span></span>
<span class="line"><span>键鼠高度 = 身高x0.183 + 椅面高度 - 6</span></span>
<span class="line"><span>写字高度 = 键鼠高度 + 5</span></span></code></pre></div><ul><li><p>国标GB/T 14776—93，推荐桌面高度：<img src="https://s2.loli.net/2022/06/30/5AcvHaPN9hDxmy7.jpg" alt="人体工学桌面高度.jpg"></p></li><li><p>按<strong>键鼠高度</strong>买<strong>钢木桌</strong>。不伏案写字。便宜实惠。注意用显示器原厂底座，显示器会过低。考虑买支架或自行垫高。</p></li><li><p>钢木桌也可以买宜家的可调节高度桌腿，桌板淘宝有实木的，也可以买宜家夹板。</p></li><li><p>电动升降桌。</p><ul><li><p>平常保持键鼠高度，伏案写字就升上来一点。</p></li><li><p>电动升降桌保持伏案高度，键鼠高度另买一个小钢木桌放在升降桌下面。</p></li></ul></li><li><p>电子琴桌，托架够大可以放下键盘加鼠标，往往电脑桌只能放下键盘。</p></li></ul><h2 id="显示器尺寸与深度" tabindex="-1">显示器尺寸与深度 <a class="header-anchor" href="#显示器尺寸与深度" aria-label="Permalink to “显示器尺寸与深度”">​</a></h2><p>肉眼分辨极限点距 = 眼到屏幕距离 / 3438。（根据人眼可区分的最小视角1分角（1/60度）计算）</p><p>推荐屏幕宽度 = 人眼与屏幕的距离 × 1.154 - 6 （27寸16：9推荐眼离屏57cm）根据人眼平均视角计算看到整个屏幕不需要转脖子的最小距离。</p><h2 id="椅子" tabindex="-1">椅子 <a class="header-anchor" href="#椅子" aria-label="Permalink to “椅子”">​</a></h2><p>网易严选·小蛮腰，凑合能用的里最便宜的。</p><p>稍贵些的支家1606，网布支架等用料更好些，性价比就不错。</p><p>西昊M57等，跟Herman Miller旗下产品曲线很像的都可以。</p><p>和保友金豪曲线很像的都不推荐。故意把腰托做的很突出，营造视觉冲击力，商业噱头。找个人平躺或侧躺在硬板床上，看看放松状态下的人体自然曲线，就明白这种就是在整蛊。</p><p>普通靠背椅，可以考虑买个米乔腰靠，不需要气动，效果也是有的，通常能实现健康的中等体型久坐不腰酸背痛。</p><h2 id="坐垫" tabindex="-1">坐垫 <a class="header-anchor" href="#坐垫" aria-label="Permalink to “坐垫”">​</a></h2><p>乳胶材料非常不透气，目前来看，比较舒适透气的材料有：</p><ul><li><p>硬：空气纤维</p></li><li><p>软：硅胶纤维</p></li></ul>`,16)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};